// ============================================================
// NODE: Format ChatGPT Prompt
// PURPOSE: Extract all form fields and build the AI prompt
// ============================================================

const formData = $input.first().json;

// --- SYMPTOM EXTRACTION (30+ symptoms) ---
const symptoms = [];
const symptomFields = [
  'Headache', 'Fatigue', 'Eye strain', 'Dizziness', 'Brain fog',
  'Nausea', 'Fever', 'Cough', 'Sore throat', 'Muscle ache',
  'Joint pain', 'Anxiety', 'Insomnia', 'Difficulty concentrating',
  'Blurred vision', 'Runny nose', 'Chest tightness', 'Shortness of breath',
  'Back pain', 'Neck pain', 'Stomach ache', 'Bloating', 'Loss of appetite',
  'Heart palpitations', 'Cold hands/feet', 'Excessive sweating',
  'Skin rash', 'Hair loss', 'Low energy', 'Mood swings',
  'Irritability', 'Poor memory', 'Dry eyes', 'Dry skin'
];
for (const s of symptomFields) {
  if (formData[s] === 'Yes') symptoms.push(s);
}

// --- CONTEXT FIELDS ---
const studentEmail = formData['Email address'] || formData['Email'] || '';
const studentName  = formData['Your Name'] || formData['Name'] || 'Student';
const sleepHours   = formData['Sleep hours last night'] || 'Not provided';
const stressLevel  = formData['Stress level today (1-10)'] || 'Not provided';
const waterIntake  = formData['Water intake today'] || 'Not provided';
const screenTime   = formData['Screen time today (hours)'] || 'Not provided';
const severity     = formData['Symptom severity (1-10)'] || 'Moderate';
const duration     = formData['How long have you had these symptoms?'] || 'Not specified';
const ageRange     = formData['Age range'] || 'Not specified';
const gender       = formData['Gender'] || 'Not specified';
const exercise     = formData['Exercise today?'] || 'Not specified';
const diet         = formData['Meal quality today'] || 'Not specified';
const medCondition = formData['Any known medical conditions?'] || 'None';
const timestamp    = formData['Timestamp'] || new Date().toISOString();

// --- BUILD AI PROMPT ---
const prompt = `You are a student wellness assistant trained to analyze health symptoms and provide probabilistic condition assessments. You are NOT a replacement for a doctor.

═══════════════════════════════════
STUDENT INPUT
═══════════════════════════════════
Student Name: ${studentName}
Age Range: ${ageRange}
Gender: ${gender}
Symptoms Reported: ${symptoms.join(', ') || 'None reported'}
Sleep Last Night: ${sleepHours} hours
Stress Level: ${stressLevel}/10
Water Intake Today: ${waterIntake}
Screen Time Today: ${screenTime} hours
Exercise Today: ${exercise}
Diet Quality: ${diet}
Symptom Duration: ${duration}
Severity: ${severity}/10
Known Conditions: ${medCondition}

═══════════════════════════════════
STEP 1 — SYMPTOM ANALYSIS
═══════════════════════════════════
List which body systems are affected by the reported symptoms.

═══════════════════════════════════
STEP 2 — BIAS & FAIRNESS CHECK
═══════════════════════════════════
Note any demographic biases that may influence your prediction. Ensure analysis is fair regardless of age or gender. Output:
BIAS_NOTE: [one sentence on fairness consideration]

═══════════════════════════════════
STEP 3 — PROBABILISTIC CONDITION ASSESSMENT
═══════════════════════════════════
Return exactly 3 conditions in this exact pipe-separated format:
CONDITION_1: [name] | PROBABILITY_1: [X%] | CONFIDENCE_1: [High/Medium/Low]
CONDITION_2: [name] | PROBABILITY_2: [X%] | CONFIDENCE_2: [High/Medium/Low]
CONDITION_3: [name] | PROBABILITY_3: [X%] | CONFIDENCE_3: [High/Medium/Low]
REASONING: [2-3 sentences explaining the assessment]

═══════════════════════════════════
STEP 4 — KNOWLEDGE MAP (Symptom → Condition → Remedy)
═══════════════════════════════════
For each condition provide remedies and lifestyle factors:
REMEDY_1A: [remedy for condition 1]
REMEDY_1B: [second remedy for condition 1]
REMEDY_2A: [remedy for condition 2]
REMEDY_2B: [second remedy for condition 2]
REMEDY_3A: [remedy for condition 3]
REMEDY_3B: [second remedy for condition 3]
LIFESTYLE: [one lifestyle change applicable across conditions]

═══════════════════════════════════
STEP 5 — PERSONALIZED WELLNESS TIPS (Generative AI)
═══════════════════════════════════
Give 3 tips personalized to this student's sleep, stress, hydration, screen time, exercise, and diet:
TIP_1: [personalized tip]
TIP_2: [personalized tip]
TIP_3: [personalized tip]

═══════════════════════════════════
STEP 6 — RISK ASSESSMENT
═══════════════════════════════════
RISK_FLAG: [Low / Medium / High]
RISK_REASON: [one sentence explanation]
SEE_DOCTOR: [Yes / No / If symptoms persist]

═══════════════════════════════════
STEP 7 — WELLNESS SCORE (out of 100)
═══════════════════════════════════
SLEEP_SCORE: [X/25]
HYDRATION_SCORE: [X/25]
STRESS_SCORE: [X/25]
SCREEN_SCORE: [X/25]
TOTAL_SCORE: [X/100]
WELLNESS_TREND: [Improving / Stable / Declining — based on current data]

═══════════════════════════════════
STEP 8 — CANVA REPORT SUMMARY
═══════════════════════════════════
Generate a brief wellness report paragraph (3-5 sentences) suitable for a Canva report card:
REPORT_SUMMARY: [paragraph]

═══════════════════════════════════
⚠️ DISCLAIMER (must appear in every response)
═══════════════════════════════════
DISCLAIMER: This analysis is generated by an AI assistant for educational and wellness awareness purposes only. It is NOT a medical diagnosis. Probabilities are estimates based on symptom patterns and should not replace professional medical advice. If you are experiencing severe or persistent symptoms, please consult a qualified healthcare professional immediately.
═══════════════════════════════════`;

return [{
  json: {
    prompt,
    studentEmail,
    studentName,
    studentId: timestamp,
    ageRange,
    gender,
    rawSymptoms: symptoms.join(', '),
    sleepHours,
    stressLevel,
    waterIntake,
    screenTime,
    exercise,
    diet,
    severity,
    duration,
    medCondition
  }
}];

// ============================================================
// NODE: Parse AI Response
// PURPOSE: Extract all structured fields from Groq/LLM output
// ============================================================

const aiResponse = $input.first().json.text ||
                   ($input.first().json.choices && $input.first().json.choices[0].message.content) ||
                   '';
const promptData = $('Format ChatGPT Prompt1').first().json;

function extract(pattern, defaultValue = 'Not found') {
  const match = aiResponse.match(pattern);
  return match ? match[1].trim() : defaultValue;
}

// --- Conditions ---
const condition1   = extract(/CONDITION_1:\s*([^|\n]+)/);
const prob1        = extract(/PROBABILITY_1:\s*(\d+%)/);
const confidence1  = extract(/CONFIDENCE_1:\s*([\w]+)/);
const condition2   = extract(/CONDITION_2:\s*([^|\n]+)/);
const prob2        = extract(/PROBABILITY_2:\s*(\d+%)/);
const confidence2  = extract(/CONFIDENCE_2:\s*([\w]+)/);
const condition3   = extract(/CONDITION_3:\s*([^|\n]+)/);
const prob3        = extract(/PROBABILITY_3:\s*(\d+%)/);
const confidence3  = extract(/CONFIDENCE_3:\s*([\w]+)/);
const reasoning    = extract(/REASONING:\s*([^\n]+)/);

// --- Remedies ---
const remedy1a  = extract(/REMEDY_1A:\s*([^\n]+)/);
const remedy1b  = extract(/REMEDY_1B:\s*([^\n]+)/);
const remedy2a  = extract(/REMEDY_2A:\s*([^\n]+)/);
const remedy2b  = extract(/REMEDY_2B:\s*([^\n]+)/);
const remedy3a  = extract(/REMEDY_3A:\s*([^\n]+)/);
const remedy3b  = extract(/REMEDY_3B:\s*([^\n]+)/);
const lifestyle = extract(/LIFESTYLE:\s*([^\n]+)/);

// --- Wellness Tips ---
const tip1 = extract(/TIP_1:\s*([^\n]+)/);
const tip2 = extract(/TIP_2:\s*([^\n]+)/);
const tip3 = extract(/TIP_3:\s*([^\n]+)/);

// --- Risk ---
const riskFlag   = extract(/RISK_FLAG:\s*([\w]+)/);
const riskReason = extract(/RISK_REASON:\s*([^\n]+)/);
const seeDoctor  = extract(/SEE_DOCTOR:\s*([^\n]+)/);

// --- Scores ---
const sleepScore      = extract(/SLEEP_SCORE:\s*(\d+\/25)/);
const hydrationScore  = extract(/HYDRATION_SCORE:\s*(\d+\/25)/);
const stressScore     = extract(/STRESS_SCORE:\s*(\d+\/25)/);
const screenScore     = extract(/SCREEN_SCORE:\s*(\d+\/25)/);
const totalScore      = extract(/TOTAL_SCORE:\s*(\d+\/100)/);
const wellnessTrend   = extract(/WELLNESS_TREND:\s*([^\n]+)/);

// --- Ethics ---
const biasNote     = extract(/BIAS_NOTE:\s*([^\n]+)/);
const disclaimer   = extract(/DISCLAIMER:\s*([^\n]+)/);

// --- Canva Report ---
const reportSummary = extract(/REPORT_SUMMARY:\s*([^\n]+)/);

return [{
  json: {
    logId: 'LOG' + Date.now(),
    timestamp: new Date().toISOString(),
    studentId: promptData.studentId,
    studentName: promptData.studentName,
    studentEmail: promptData.studentEmail,
    ageRange: promptData.ageRange,
    gender: promptData.gender,
    symptomsEntered: promptData.rawSymptoms,
    medCondition: promptData.medCondition,
    condition1, prob1, confidence1,
    condition2, prob2, confidence2,
    condition3, prob3, confidence3,
    reasoning,
    remedy1a, remedy1b,
    remedy2a, remedy2b,
    remedy3a, remedy3b,
    lifestyle,
    tip1, tip2, tip3,
    wellnessTips: `${tip1} | ${tip2} | ${tip3}`,
    riskFlag, riskReason, seeDoctor,
    sleepScore, hydrationScore, stressScore, screenScore, totalScore,
    wellnessTrend,
    biasNote,
    disclaimer,
    reportSummary,
    sleepHours: promptData.sleepHours,
    stressLevel: promptData.stressLevel,
    waterIntake: promptData.waterIntake,
    screenTime: promptData.screenTime,
    exercise: promptData.exercise,
    diet: promptData.diet,
    severity: promptData.severity,
    duration: promptData.duration,
    fullResponse: aiResponse,
    disclaimerAdded: 'Yes',
    promptVersion: 'v2.0'
  }
}];

// ============================================================
// NODE: Calculate Reward Points
// PURPOSE: Point-based habit reward system (Reinforcement Learning)
// Connects to Module 4: Reinforcement Learning concepts (Lecture 19)
// ============================================================

const data = $input.first().json;

// Parse numeric values safely
function parseNum(val) {
  if (typeof val === 'number') return val;
  const m = String(val).match(/\d+(\.\d+)?/);
  return m ? parseFloat(m[0]) : 0;
}

const sleepHours  = parseNum(data.sleepHours);
const stressLevel = parseNum(data.stressLevel);
const screenTime  = parseNum(data.screenTime);
const totalScore  = parseNum(data.totalScore);
const severity    = parseNum(data.severity);

let points = 0;
const badges = [];
const breakdown = [];

// --- Sleep (max 15 pts) ---
if (sleepHours >= 8) {
  points += 15; badges.push('Sleep Champion 🌙');
  breakdown.push('Sleep 8h+: +15');
} else if (sleepHours >= 7) {
  points += 10; badges.push('Good Sleeper 😴');
  breakdown.push('Sleep 7-8h: +10');
} else if (sleepHours >= 6) {
  points += 5;
  breakdown.push('Sleep 6-7h: +5');
}

// --- Hydration (max 15 pts) ---
const wi = String(data.waterIntake).toLowerCase();
if (wi.includes('3l') || wi.includes('3+ l') || wi.includes('3 l')) {
  points += 15; badges.push('Super Hydrated 💧');
  breakdown.push('Water 3L+: +15');
} else if (wi.includes('2l') || wi.includes('2-3') || wi.includes('2 l')) {
  points += 10; badges.push('Well Hydrated 💦');
  breakdown.push('Water 2L+: +10');
} else if (wi.includes('1l') || wi.includes('1-2')) {
  points += 5;
  breakdown.push('Water 1L+: +5');
}

// --- Screen Time (max 10 pts) ---
if (screenTime < 2) {
  points += 10; badges.push('Screen Detox 📵');
  breakdown.push('Screen <2h: +10');
} else if (screenTime <= 4) {
  points += 7; badges.push('Low Screen Time 📱');
  breakdown.push('Screen 2-4h: +7');
} else if (screenTime <= 6) {
  points += 3;
  breakdown.push('Screen 4-6h: +3');
}

// --- Stress (max 10 pts) ---
if (stressLevel <= 3) {
  points += 10; badges.push('Zen Master 🧘');
  breakdown.push('Stress ≤3: +10');
} else if (stressLevel <= 5) {
  points += 7; badges.push('Chill Vibes 😌');
  breakdown.push('Stress ≤5: +7');
} else if (stressLevel <= 7) {
  points += 3;
  breakdown.push('Stress ≤7: +3');
}

// --- Exercise Bonus (max 10 pts) ---
const ex = String(data.exercise).toLowerCase();
if (ex.includes('yes') || ex.includes('gym') || ex.includes('run') || ex.includes('walk')) {
  points += 10; badges.push('Active Student 🏃');
  breakdown.push('Exercised: +10');
}

// --- Wellness Score Bonus (max 15 pts) ---
if (totalScore >= 80) {
  points += 15; badges.push('Wellness Champion 🏆');
  breakdown.push('Score 80+: +15');
} else if (totalScore >= 65) {
  points += 10; badges.push('Wellness Warrior 💪');
  breakdown.push('Score 65+: +10');
} else if (totalScore >= 50) {
  points += 5;
  breakdown.push('Score 50+: +5');
}

// --- Symptom Severity Penalty ---
if (severity >= 8) {
  points = Math.max(0, points - 5);
  breakdown.push('High Severity: -5');
}

// --- Achievement Level ---
let level = 'Beginner 🌱';
if (points >= 60) level = 'Elite Wellness 🥇';
else if (points >= 45) level = 'Advanced 🥈';
else if (points >= 30) level = 'Intermediate 🥉';
else if (points >= 15) level = 'Progressing 📈';

return [{
  json: {
    entryId: 'RP' + Date.now(),
    date: data.timestamp,
    studentId: data.studentId,
    studentName: data.studentName,
    slept7Plus: sleepHours >= 7 ? 'Yes' : 'No',
    sleepPoints: sleepHours >= 8 ? 15 : sleepHours >= 7 ? 10 : sleepHours >= 6 ? 5 : 0,
    drank2LPlus: (wi.includes('2l') || wi.includes('2-3') || wi.includes('3l')) ? 'Yes' : 'No',
    waterPoints: wi.includes('3l') ? 15 : (wi.includes('2l') || wi.includes('2-3')) ? 10 : wi.includes('1l') ? 5 : 0,
    lowScreenTime: screenTime <= 4 ? 'Yes' : 'No',
    screenPoints: screenTime < 2 ? 10 : screenTime <= 4 ? 7 : screenTime <= 6 ? 3 : 0,
    stressUnder5: stressLevel <= 5 ? 'Yes' : 'No',
    stressPoints: stressLevel <= 3 ? 10 : stressLevel <= 5 ? 7 : stressLevel <= 7 ? 3 : 0,
    exercised: (ex.includes('yes') || ex.includes('gym') || ex.includes('run') || ex.includes('walk')) ? 'Yes' : 'No',
    exercisePoints: (ex.includes('yes') || ex.includes('gym') || ex.includes('run') || ex.includes('walk')) ? 10 : 0,
    wellnessBonus: totalScore >= 80 ? 15 : totalScore >= 65 ? 10 : totalScore >= 50 ? 5 : 0,
    dailyPointsTotal: points,
    badgesEarned: badges.join(', ') || 'Keep going! 💙',
    achievementLevel: level,
    pointBreakdown: breakdown.join(' | ')
  }
}];
